    <text x="20" y="44" fill="#a1a1aa" font-size="13" font-family="sans-serif">Konzeptionelle Renditeverteilung · vereinfachte Darstellung einer rechtsschiefen Form mit dicken Rändern</text>
    <polygon points="40,280 40,278 80,270 120,250 160,210 200,160 240,120 270,100 300,95 330,105 360,125 400,155 400,280" fill="#f87171" opacity="0.16"/>
    <polygon points="400,280 400,155 440,185 480,210 520,230 560,245 600,258 640,268 660,272 660,280" fill="#4ade80" opacity="0.16"/>
    <polyline points="40,278 80,270 120,250 160,210 200,160 240,120 270,100 300,95 330,105 360,125 400,155 440,185 480,210 520,230 560,245 600,258 640,268 660,272" fill="none" stroke="#e5e7eb" stroke-width="2.5"/>
    <line x1="40" y1="280" x2="660" y2="280" stroke="#52525b" stroke-width="1.5"/>
